module decalper_eb_ot_sdeen_pot_pi_dehcac_xnilix_xbus2axi4_bridge
   (m_axi_wvalid,
    m_axi_arvalid,
    m_axi_awvalid,
    state,
    clk,
    awvalid_reg_0,
    arvalid,
    FSM_sequential_state_reg_0,
    m_axi_awready,
    awvalid_reg_1,
    m_axi_wready);
  output m_axi_wvalid;
  output m_axi_arvalid;
  output m_axi_awvalid;
  output state;
  input clk;
  input awvalid_reg_0;
  input arvalid;
  input FSM_sequential_state_reg_0;
  input m_axi_awready;
  input awvalid_reg_1;
  input m_axi_wready;

  wire FSM_sequential_state_reg_0;
  wire arvalid;
  wire awvalid;
  wire awvalid_reg_0;
  wire awvalid_reg_1;
  wire clk;
  wire m_axi_arvalid;
  wire m_axi_awready;
  wire m_axi_awvalid;
  wire m_axi_wready;
  wire m_axi_wvalid;
  wire state;
  wire wvalid;

  (* FSM_ENCODED_STATES = "iSTATE:0,s_single:1,s_burst_run:10,s_burst_end:11," *) 
  FDCE FSM_sequential_state_reg
       (.C(clk),
        .CE(1'b1),
        .CLR(awvalid_reg_0),
        .D(FSM_sequential_state_reg_0),
        .Q(state));
  FDCE arvalid_reg
       (.C(clk),
        .CE(1'b1),
        .CLR(awvalid_reg_0),
        .D(arvalid),
        .Q(m_axi_arvalid));
  LUT4 #(
    .INIT(16'hFF08)) 
    awvalid_i_1
       (.I0(state),
        .I1(m_axi_awvalid),
        .I2(m_axi_awready),
        .I3(awvalid_reg_1),
        .O(awvalid));
  FDCE awvalid_reg
       (.C(clk),
        .CE(1'b1),
        .CLR(awvalid_reg_0),
        .D(awvalid),
        .Q(m_axi_awvalid));
  LUT4 #(
    .INIT(16'hFF08)) 
    wvalid_i_1
       (.I0(state),
        .I1(m_axi_wvalid),
        .I2(m_axi_wready),
        .I3(awvalid_reg_1),
        .O(wvalid));
  FDCE wvalid_reg
       (.C(clk),
        .CE(1'b1),
        .CLR(awvalid_reg_0),
        .D(wvalid),
        .Q(m_axi_wvalid));
endmodule
`ifndef GLBL
`define GLBL
`timescale  1 ps / 1 ps

module glbl ();

    parameter ROC_WIDTH = 100000;
    parameter TOC_WIDTH = 0;

//--------   STARTUP Globals --------------
    wire GSR;
    wire GTS;
    wire GWE;
    wire PRLD;
    tri1 p_up_tmp;
    tri (weak1, strong0) PLL_LOCKG = p_up_tmp;

    wire PROGB_GLBL;
    wire CCLKO_GLBL;
    wire FCSBO_GLBL;
    wire [3:0] DO_GLBL;
    wire [3:0] DI_GLBL;
   
    reg GSR_int;
    reg GTS_int;
    reg PRLD_int;

//--------   JTAG Globals --------------
    wire JTAG_TDO_GLBL;
    wire JTAG_TCK_GLBL;
    wire JTAG_TDI_GLBL;
    wire JTAG_TMS_GLBL;
    wire JTAG_TRST_GLBL;

    reg JTAG_CAPTURE_GLBL;
    reg JTAG_RESET_GLBL;
    reg JTAG_SHIFT_GLBL;
    reg JTAG_UPDATE_GLBL;
    reg JTAG_RUNTEST_GLBL;

    reg JTAG_SEL1_GLBL = 0;
    reg JTAG_SEL2_GLBL = 0 ;
    reg JTAG_SEL3_GLBL = 0;
    reg JTAG_SEL4_GLBL = 0;

    reg JTAG_USER_TDO1_GLBL = 1'bz;
    reg JTAG_USER_TDO2_GLBL = 1'bz;
    reg JTAG_USER_TDO3_GLBL = 1'bz;
    reg JTAG_USER_TDO4_GLBL = 1'bz;

    assign (strong1, weak0) GSR = GSR_int;
    assign (strong1, weak0) GTS = GTS_int;
    assign (weak1, weak0) PRLD = PRLD_int;

    initial begin
	GSR_int = 1'b1;
	PRLD_int = 1'b1;
	#(ROC_WIDTH)
	GSR_int = 1'b0;
	PRLD_int = 1'b0;
    end

    initial begin
	GTS_int = 1'b1;
	#(TOC_WIDTH)
	GTS_int = 1'b0;
    end

endmodule
`endif
